code = """import json
import pandas as pd

# Load the articles
with open(locals()['var_function-call-4127698444615500778'], 'r') as f:
    articles = json.load(f)

df = pd.DataFrame(articles)
df['desc_len'] = df['description'].apply(lambda x: len(x) if x else 0)
df = df.sort_values('desc_len', ascending=False)

# Keywords
sports_keywords = ['olympic', 'medal', 'athens', 'team', 'game', 'cup', 'champion', 'league', 'football', 'basketball', 'baseball', 'soccer', 'tennis', 'hockey', 'sport', 'athlete', 'coach', 'tournament', 'match', 'win', 'score', 'nba', 'nfl', 'mlb', 'sox', 'yankees', 'lakers', 'paralympic', 'gold', 'silver', 'bronze', 'marathon', 'sprint', 'relay', 'swim', 'gymnast', 'race', 'driver', 'f1']

def is_sports(text):
    text = text.lower()
    score = 0
    matched = []
    for k in sports_keywords:
        if k in text:
            score += 1
            matched.append(k)
    return score, matched

candidates = []
# Check indices 10 to 60
for index, row in df.iloc[10:60].iterrows():
    title = row['title']
    desc = row['description']
    score, matched = is_sports(title + " " + desc)
    if score > 0:
        candidates.append({
            "title": title,
            "desc_len": row['desc_len'],
            "sports_score": score,
            "matched_keywords": matched,
            "description": desc
        })

print("__RESULT__:")
print(json.dumps(candidates))"""

